import torch.nn as nn
from mamba_ssm import Mamba

class MambaBlock(nn.Module):
    def __init__(self, d_model, d_state=16, d_conv=4, expand=2):
        super().__init__()
        self.norm = nn.LayerNorm(d_model)
        self.ssm  = Mamba(d_model, d_state=d_state, d_conv=d_conv, expand=expand)

    def forward(self, x):
        return x + self.ssm(self.norm(x))  # pre-norm + residual

class MambaLM(nn.Module):
    def __init__(self, vocab_size, d_model=512, n_layers=12, d_state=16):
        super().__init__()
        self.embed   = nn.Embedding(vocab_size, d_model)
        self.layers  = nn.ModuleList([MambaBlock(d_model, d_state) for _ in range(n_layers)])
        self.norm    = nn.LayerNorm(d_model)
        self.lm_head = nn.Linear(d_model, vocab_size, bias=False)

    def forward(self, input_ids):
        x = self.embed(input_ids)
        for layer in self.layers:
            x = layer(x)
        return self.lm_head(self.norm(x))
